"use strict";(globalThis.webpackChunk_cludix_doc=globalThis.webpackChunk_cludix_doc||[]).push([[8130],{77735:n=>{n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"self-hosted-lightweight-cloud-webdav","metadata":{"permalink":"/blog/self-hosted-lightweight-cloud-webdav","editUrl":"https://github.com/yunqilee69/cludix-doc/tree/master/blog/2026-07-06-\u81ea\u5efa\u8f7b\u91cf\u5316\u7f51\u76d8\u4e0eWebDAV.md","source":"@site/blog/2026-07-06-\u81ea\u5efa\u8f7b\u91cf\u5316\u7f51\u76d8\u4e0eWebDAV.md","title":"\u81ea\u5efa\u8f7b\u91cf\u5316\u7f51\u76d8\u4e0e WebDAV\uff1a\u7528 dufs \u66ff\u4ee3\u91cd\u91cf\u7ea7\u65b9\u6848","description":"\u4f60\u662f\u5426\u60f3\u8fc7\u5728\u5bb6\u5ead\u670d\u52a1\u5668\u6216 VPS \u4e0a\u642d\u4e00\u4e2a\u7f51\u76d8\uff0c\u5374\u53d1\u73b0 Nextcloud \u592a\u91cd\u3001ownCloud \u592a\u81c3\u80bf\uff0c\u800c Samba \u53c8\u53ea\u80fd\u5728\u5185\u7f51\u7528\uff1f\u672c\u6587\u4ecb\u7ecd\u4e00\u4e2a\u7528 Rust \u7f16\u5199\u7684\u6781\u7b80\u6587\u4ef6\u670d\u52a1\u5668 dufs\uff0c\u5b83\u540c\u65f6\u63d0\u4f9b Web \u6587\u4ef6\u7ba1\u7406\u548c WebDAV \u534f\u8bae\u652f\u6301\uff0c\u4e00\u6761\u547d\u4ee4\u5373\u53ef\u542f\u52a8\uff0cDocker \u90e8\u7f72\u4e5f\u53ea\u9700\u51e0\u884c\u914d\u7f6e\u3002","date":"2026-07-06T19:30:00.000Z","tags":[{"inline":true,"label":"dufs","permalink":"/blog/tags/dufs"},{"inline":true,"label":"webdav","permalink":"/blog/tags/webdav"},{"inline":true,"label":"docker","permalink":"/blog/tags/docker"},{"inline":true,"label":"storage","permalink":"/blog/tags/storage"}],"readingTime":5.71,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"self-hosted-lightweight-cloud-webdav","title":"\u81ea\u5efa\u8f7b\u91cf\u5316\u7f51\u76d8\u4e0e WebDAV\uff1a\u7528 dufs \u66ff\u4ee3\u91cd\u91cf\u7ea7\u65b9\u6848","date":"2026-07-06 19:30","tags":["dufs","webdav","docker","storage"]},"unlisted":false,"nextItem":{"title":"Jenkins \u5168\u94fe\u8def\u90e8\u7f72\u5b9e\u6218\uff1a\u4ece Git Push \u5230 Nginx \u91cd\u8f7d","permalink":"/blog/jenkins-fullstack-deploy-guide"}},"content":"\u4f60\u662f\u5426\u60f3\u8fc7\u5728\u5bb6\u5ead\u670d\u52a1\u5668\u6216 VPS \u4e0a\u642d\u4e00\u4e2a\u7f51\u76d8\uff0c\u5374\u53d1\u73b0 Nextcloud \u592a\u91cd\u3001ownCloud \u592a\u81c3\u80bf\uff0c\u800c Samba \u53c8\u53ea\u80fd\u5728\u5185\u7f51\u7528\uff1f\u672c\u6587\u4ecb\u7ecd\u4e00\u4e2a\u7528 Rust \u7f16\u5199\u7684\u6781\u7b80\u6587\u4ef6\u670d\u52a1\u5668 **dufs**\uff0c\u5b83\u540c\u65f6\u63d0\u4f9b Web \u6587\u4ef6\u7ba1\u7406\u548c WebDAV \u534f\u8bae\u652f\u6301\uff0c\u4e00\u6761\u547d\u4ee4\u5373\u53ef\u542f\u52a8\uff0cDocker \u90e8\u7f72\u4e5f\u53ea\u9700\u51e0\u884c\u914d\u7f6e\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u4e3a\u4ec0\u4e48\u9700\u8981\u4e00\u4e2a\u8f7b\u91cf\u5316\u7f51\u76d8\\n\\n\u5e38\u89c1\u7684\u6587\u4ef6\u5171\u4eab\u9700\u6c42\u5176\u5b9e\u5f88\u6734\u7d20\uff1a\\n\\n- \u624b\u673a\u60f3\u8bbf\u95ee\u7535\u8111\u4e0a\u7684\u67d0\u4e2a\u6587\u4ef6\\n- \u5c40\u57df\u7f51\u5185\u7ed9\u540c\u4e8b\u4f20\u4e2a\u5927\u6587\u4ef6\\n- \u5728\u5916\u9762\u60f3\u8fdc\u7a0b\u8bbf\u95ee\u5bb6\u91cc\u7684\u8d44\u6599\\n- \u7ed9\u5907\u4efd\u5de5\u5177\uff08Rclone\u3001Restic\uff09\u63d0\u4f9b\u4e00\u4e2a WebDAV \u76ee\u6807\\n\\n\u5982\u679c\u4f60\u7528\u8fc7 Nextcloud \u6216 ownCloud\uff0c\u5927\u6982\u4f1a\u611f\u53d7\u5230\uff1a\u4e3a\u4e86\u5b9e\u73b0\u8fd9\u4e9b\u7b80\u5355\u7684\u9700\u6c42\uff0c\u4f60\u5f97\u7ef4\u62a4\u4e00\u5957 LAMP/LEMP \u73af\u5883\u3001\u4e00\u4e2a\u6570\u636e\u5e93\u3001\u5b9a\u671f\u7684\u5b89\u5168\u66f4\u65b0\u2014\u2014\u8fd9\u8fd8\u6ca1\u7b97\u4e0a PHP \u5e26\u6765\u7684\u6027\u80fd\u5f00\u9500\u3002\u5bf9\u4e8e\u4e2a\u4eba\u6216\u5c0f\u56e2\u961f\u6765\u8bf4\uff0c\u8fd9\u5957\u65b9\u6848\u8fc7\u4e8e\u6c89\u91cd\u3002\\n\\n\u53e6\u4e00\u65b9\u9762\uff0c`python3 -m http.server` \u5012\u662f\u8f7b\u91cf\uff0c\u4f46\u53ea\u80fd\u4e0b\u8f7d\u3001\u4e0d\u80fd\u4e0a\u4f20\uff0c\u66f4\u522b\u63d0\u641c\u7d22\u548c\u6743\u9650\u63a7\u5236\u4e86\u3002\\n\\n**dufs** \u521a\u597d\u586b\u8865\u4e86\u8fd9\u4e2a\u7a7a\u767d\uff1a\u4e00\u4e2a Rust \u7f16\u5199\u7684\u5355\u4e8c\u8fdb\u5236\u6587\u4ef6\u670d\u52a1\u5668\uff0c\u540c\u65f6\u63d0\u4f9b Web UI \u548c WebDAV \u534f\u8bae\uff0c\u652f\u6301\u4e0a\u4f20\u3001\u641c\u7d22\u3001\u6743\u9650\u63a7\u5236\uff0c\u751a\u81f3\u53ef\u4ee5\u7528 curl \u5b8c\u6210\u6240\u6709\u64cd\u4f5c\u3002\\n\\n## dufs \u662f\u4ec0\u4e48\\n\\n[dufs](https://github.com/sigoden/dufs) \u662f\u4e00\u4e2a\u7528 Rust \u7f16\u5199\u7684\u8f7b\u91cf\u7ea7\u6587\u4ef6\u670d\u52a1\u5668\uff0c\u6838\u5fc3\u7279\u6027\uff1a\\n\\n| \u80fd\u529b | \u8bf4\u660e |\\n| --- | --- |\\n| \u9759\u6001\u6587\u4ef6\u670d\u52a1 | \u6d4f\u89c8\u5668\u76f4\u63a5\u67e5\u770b\u548c\u4e0b\u8f7d\u6587\u4ef6 |\\n| \u6587\u4ef6\u4e0a\u4f20 | \u62d6\u62fd\u4e0a\u4f20\u6587\u4ef6\u548c\u6587\u4ef6\u5939 |\\n| \u6587\u4ef6\u7ba1\u7406 | \u5728\u7ebf\u521b\u5efa\u3001\u7f16\u8f91\u3001\u641c\u7d22\u3001\u5220\u9664 |\\n| \u76ee\u5f55\u6253\u5305\u4e0b\u8f7d | \u6574\u4e2a\u6587\u4ef6\u5939\u4e0b\u8f7d\u4e3a ZIP |\\n| \u65ad\u70b9\u7eed\u4f20 | \u652f\u6301\u5927\u6587\u4ef6\u7684\u5206\u5757\u4e0a\u4f20/\u4e0b\u8f7d |\\n| \u6743\u9650\u63a7\u5236 | \u57fa\u4e8e\u8d26\u53f7\u7684\u8def\u5f84\u7ea7\u8bfb\u5199\u6743\u9650 |\\n| WebDAV \u534f\u8bae | \u53ef\u4f5c\u4e3a\u7f51\u7edc\u78c1\u76d8\u6302\u8f7d |\\n| HTTPS | \u5185\u7f6e TLS \u8bc1\u4e66\u652f\u6301 |\\n| curl \u53cb\u597d | \u6240\u6709\u64cd\u4f5c\u5747\u53ef\u901a\u8fc7 curl \u5b8c\u6210 |\\n| \u5065\u5eb7\u68c0\u67e5 | \u5185\u7f6e `/__dufs__/health` \u7aef\u70b9 |\\n\\n\u4e00\u4e2a\u4e8c\u8fdb\u5236\u3001\u96f6\u4f9d\u8d56\u3001\u9ed8\u8ba4\u7aef\u53e3 5000\uff0c`dufs` \u4e00\u6761\u547d\u4ee4\u5373\u53ef\u542f\u52a8\u3002\\n\\n## WebDAV\uff1a\u88ab\u4f4e\u4f30\u7684\u534f\u8bae\\n\\nWebDAV\uff08Web Distributed Authoring and Versioning\uff09\u662f HTTP \u7684\u6269\u5c55\u534f\u8bae\uff0c\u5728\u6807\u51c6 HTTP \u65b9\u6cd5\uff08GET\u3001PUT\u3001DELETE\uff09\u57fa\u7840\u4e0a\u589e\u52a0\u4e86 PROPFIND\u3001MKCOL\u3001COPY\u3001MOVE \u7b49\u65b9\u6cd5\uff0c\u4f7f\u5f97\u5ba2\u6237\u7aef\u53ef\u4ee5\u50cf\u64cd\u4f5c\u672c\u5730\u6587\u4ef6\u7cfb\u7edf\u4e00\u6837\u64cd\u4f5c\u8fdc\u7a0b\u6587\u4ef6\u3002\\n\\n### \u4e3a\u4ec0\u4e48 WebDAV \u91cd\u8981\\n\\n1. **\u7cfb\u7edf\u7ea7\u6302\u8f7d**\uff1aWindows\u3001macOS\u3001Linux \u539f\u751f\u652f\u6301\u5c06 WebDAV \u6620\u5c04\u4e3a\u7f51\u7edc\u9a71\u52a8\u5668\uff0c\u6587\u4ef6\u7ba1\u7406\u5668\u76f4\u63a5\u8bbf\u95ee\\n2. **\u5e94\u7528\u751f\u6001\u4e30\u5bcc**\uff1a\u5927\u91cf\u7b14\u8bb0\u8f6f\u4ef6\uff08Joplin\uff09\u3001\u5907\u4efd\u5de5\u5177\uff08Rclone\u3001Restic\u3001Duplicati\uff09\u3001\u540c\u6b65\u5de5\u5177\u539f\u751f\u652f\u6301 WebDAV\\n3. **\u8de8\u5e73\u53f0**\uff1a\u4e0d\u4f9d\u8d56\u7279\u5b9a\u5ba2\u6237\u7aef\uff0c\u4efb\u4f55\u652f\u6301 WebDAV \u7684\u8f6f\u4ef6\u90fd\u80fd\u5bf9\u63a5\\n4. **HTTP \u57fa\u7840**\uff1a\u8d70\u6807\u51c6 HTTP/HTTPS \u7aef\u53e3\uff0c\u7a7f\u900f\u9632\u706b\u5899\u548c\u4ee3\u7406\u5929\u7136\u53cb\u597d\\n\\n### \u5404\u5e73\u53f0 WebDAV \u5ba2\u6237\u7aef\\n\\n| \u5e73\u53f0 | \u5ba2\u6237\u7aef | \u8bf4\u660e |\\n| --- | --- | --- |\\n| **Windows** | \u8d44\u6e90\u7ba1\u7406\u5668\uff08\u539f\u751f\uff09 | \u6620\u5c04\u7f51\u7edc\u9a71\u52a8\u5668\uff0c\u4f46\u6709 50MB \u9ed8\u8ba4\u6587\u4ef6\u5927\u5c0f\u9650\u5236 |\\n| **Windows** | [RaiDrive](https://www.raidrive.com/)\uff08\u514d\u8d39\uff09 | \u4f53\u9a8c\u6700\u597d\uff0c\u652f\u6301 WebDAV/SFTP/FTP\uff0c\u50cf\u672c\u5730\u78c1\u76d8\u4e00\u6837\u4f7f\u7528 |\\n| **Windows** | ExpanDrive / NetDrive | \u5546\u4e1a\u8f6f\u4ef6\uff0c\u7a33\u5b9a\u6027\u66f4\u597d |\\n| **macOS** | Finder\uff08\u539f\u751f\uff09 | \u300c\u8fde\u63a5\u670d\u52a1\u5668\u300d\u8f93\u5165\u5730\u5740\u5373\u53ef\uff0c\u4f46\u5927\u6587\u4ef6\u548c\u91cd\u8fde\u4f53\u9a8c\u4e00\u822c |\\n| **macOS** | ExpanDrive / NetDrive | \u4f7f\u7528 File Provider API\uff0c\u66f4\u7a33\u5b9a |\\n| **Linux** | davfs2 | `mount -t davfs` \u6302\u8f7d\uff0c\u4f46\u9879\u76ee\u5df2\u4e0d\u592a\u6d3b\u8dc3 |\\n| **Linux** | RaiDrive CLI | \u652f\u6301 Debian/RHEL/Alpine \u7b49\u53d1\u884c\u7248 |\\n| **\u79fb\u52a8\u7aef** | \u5404\u5e73\u53f0 WebDAV App | iOS/Android \u5747\u6709\u5927\u91cf WebDAV \u5ba2\u6237\u7aef |\\n\\n> \ud83d\udca1 **Windows \u539f\u751f WebDAV \u7684\u5751**\uff1a\u9ed8\u8ba4 50MB \u6587\u4ef6\u5927\u5c0f\u9650\u5236\u9700\u8981\u6539\u6ce8\u518c\u8868\uff08`FileSizeLimitInBytes`\uff09\uff0c\u4e14\u4f7f\u7528 HTTPS \u65f6\u8bc1\u4e66\u9a8c\u8bc1\u8f83\u4e25\u683c\u3002\u63a8\u8350\u7528 RaiDrive \u66ff\u4ee3\u3002\\n\\n## \u6743\u9650\u63a7\u5236\u4e0e\u9274\u6743\\n\\ndufs \u7684\u6743\u9650\u6a21\u578b\u8bbe\u8ba1\u5f97\u7b80\u6d01\u4f46\u591f\u7528\uff0c\u6838\u5fc3\u662f **\u8d26\u53f7 + \u8def\u5f84 + \u6743\u9650** \u4e09\u5143\u7ec4\uff1a\\n\\n### \u9274\u6743\u65b9\u5f0f\\n\\ndufs \u540c\u65f6\u652f\u6301 **Basic Auth** \u548c **Digest Auth**\uff0c\u9ed8\u8ba4\u4f7f\u7528 Digest Auth\uff08\u66f4\u5b89\u5168\uff0c\u5bc6\u7801\u4e0d\u5728\u7f51\u7edc\u4e2d\u660e\u6587\u4f20\u8f93\uff09\u3002\\n\\n```bash\\n# Digest Auth\uff08\u9ed8\u8ba4\uff09\\ncurl --user admin:pass123 --digest http://your-server:5000/\\n\\n# Basic Auth\\ncurl --user admin:pass123 http://your-server:5000/\\n```\\n\\n### \u6743\u9650\u89c4\u5219\u683c\u5f0f\\n\\n```bash\\n-a \\"\u7528\u6237\u540d:\u5bc6\u7801@/\u8def\u5f84:\u6743\u9650\\"\\n```\\n\\n- `:rw` \u8868\u793a\u8bfb\u5199\u6743\u9650\uff0c\u4e0d\u52a0\u5219\u53ea\u8bfb\\n- `@/` \u524d\u9762\u4e0d\u5199\u7528\u6237\u540d\u5bc6\u7801\u8868\u793a\u533f\u540d\u7528\u6237\\n- \u591a\u6761\u89c4\u5219\u7528 `|` \u5206\u9694\\n\\n### \u5b9e\u9645\u573a\u666f\u793a\u4f8b\\n\\n```bash\\n# \u7ba1\u7406\u5458\uff1a\u5b8c\u5168\u8bfb\u5199\u6743\u9650\\n-a \\"admin:secretpass@/:rw\\"\\n\\n# \u666e\u901a\u7528\u6237\uff1a\u53ea\u80fd\u8bfb\u5199 /share \u76ee\u5f55\\n-a \\"user:userpass@/share:rw\\"\\n\\n# \u533f\u540d\u7528\u6237\uff1a\u53ea\u8bfb\u8bbf\u95ee /public \u76ee\u5f55\\n-a \\"@/public\\"\\n\\n# \u7ec4\u5408\uff1a\u7ba1\u7406\u5458\u5168\u6743 + \u533f\u540d\u53ea\u8bfb\\n-a \\"admin:secretpass@/:rw|@/\\"\\n```\\n\\n### \u91cd\u8981\u7ec6\u8282\\n\\n**\u8d26\u53f7\u6743\u9650\u53d7\u5168\u5c40\u6743\u9650\u7ea6\u675f**\u3002\u5982\u679c dufs \u542f\u52a8\u65f6\u6ca1\u6709\u5f00\u542f `--allow-upload`\uff0c\u5373\u4f7f\u8d26\u53f7\u88ab\u6388\u4e88 `:rw` \u6743\u9650\uff0c\u4e5f\u65e0\u6cd5\u4e0a\u4f20\u3002\u8fd9\u610f\u5473\u7740\u4f60\u53ef\u4ee5\u7528\u5168\u5c40\u5f00\u5173\u505a\u786c\u6027\u9650\u5236\uff0c\u7528\u8d26\u53f7\u6743\u9650\u505a\u7ec6\u7c92\u5ea6\u63a7\u5236\u3002\\n\\ndufs \u8fd8\u652f\u6301 **\u54c8\u5e0c\u5bc6\u7801**\uff0c\u907f\u514d\u5728\u547d\u4ee4\u884c\u6216\u914d\u7f6e\u6587\u4ef6\u4e2d\u66b4\u9732\u660e\u6587\u5bc6\u7801\uff0c\u5bf9\u751f\u4ea7\u73af\u5883\u66f4\u53cb\u597d\u3002\\n\\n## \u548c\u5176\u4ed6\u65b9\u6848\u5bf9\u6bd4\\n\\n| \u7279\u6027 | dufs | Filebrowser | Nextcloud | Samba |\\n| --- | --- | --- | --- | --- |\\n| \u90e8\u7f72\u590d\u6742\u5ea6 | \u4e00\u6761\u547d\u4ee4 | Docker / \u4e8c\u8fdb\u5236 | LAMP + DB | \u7cfb\u7edf\u7ea7\u5b89\u88c5 |\\n| \u5185\u5b58\u5360\u7528 | ~10MB | ~30MB | 512MB+ | ~50MB |\\n| Web UI | \u7b80\u6d01 | \u5b8c\u6574 | \u529f\u80fd\u4e30\u5bcc | \u65e0 |\\n| WebDAV | \u539f\u751f\u652f\u6301 | \u4e0d\u652f\u6301 | \u652f\u6301 | \u4e0d\u652f\u6301 |\\n| \u6743\u9650\u63a7\u5236 | \u8def\u5f84\u7ea7 | \u7528\u6237\u7ea7 | \u5b8c\u6574 ACL | \u7cfb\u7edf\u7528\u6237\u7ea7 |\\n| \u6587\u4ef6\u7f16\u8f91 | \u5728\u7ebf\u7f16\u8f91 | \u5728\u7ebf\u7f16\u8f91 | \u5728\u7ebf\u7f16\u8f91 + \u534f\u4f5c | \u65e0 |\\n| \u641c\u7d22 | \u5185\u7f6e | \u5185\u7f6e | \u5168\u6587\u641c\u7d22 | \u65e0 |\\n| \u5916\u7f51\u8bbf\u95ee | HTTP \u76f4\u63a5 | \u53cd\u4ee3 | \u53cd\u4ee3 | \u9700 VPN |\\n| \u9002\u7528\u573a\u666f | \u8f7b\u91cf\u5171\u4eab + WebDAV | \u7eaf Web \u6587\u4ef6\u7ba1\u7406 | \u56e2\u961f\u534f\u4f5c | \u5185\u7f51\u5171\u4eab |\\n\\n**\u9009\u62e9\u5efa\u8bae**\uff1a\\n\\n- \u9700\u8981\u56e2\u961f\u534f\u4f5c\u3001\u65e5\u5386\u3001\u8054\u7cfb\u4eba \u2192 **Nextcloud**\\n- \u53ea\u9700\u8981 Web \u6587\u4ef6\u7ba1\u7406\u754c\u9762 \u2192 **Filebrowser**\uff08\u672c\u7ad9\u4e5f\u6709[\u90e8\u7f72\u6559\u7a0b](../docs/tutorials/docker/deployments/Filebrowser\u90e8\u7f72)\uff09\\n- \u9700\u8981\u8f7b\u91cf + WebDAV + \u6587\u4ef6\u7ba1\u7406 \u2192 **dufs**\\n- \u7eaf\u5185\u7f51\u5171\u4eab\u3001\u4e0d\u9700\u8981\u5916\u7f51\u8bbf\u95ee \u2192 **Samba**\\n\\n## \u6211\u7684\u7528\u6cd5\\n\\n\u6211\u7684\u5178\u578b\u4f7f\u7528\u573a\u666f\uff1a\\n\\n1. **\u7f51\u76d8\u66ff\u4ee3**\uff1a\u6d4f\u89c8\u5668\u8bbf\u95ee dufs \u7684 Web UI \u4e0a\u4f20\u4e0b\u8f7d\u6587\u4ef6\uff0c\u624b\u673a\u548c\u7535\u8111\u901a\u7528\\n2. **WebDAV \u6302\u8f7d**\uff1aWindows \u4e0a\u7528 RaiDrive \u628a dufs \u6302\u8f7d\u4e3a\u672c\u5730\u78c1\u76d8\uff0c\u50cf\u64cd\u4f5c\u672c\u5730\u6587\u4ef6\u4e00\u6837\u64cd\u4f5c\u8fdc\u7a0b\u6587\u4ef6\\n3. **\u5907\u4efd\u76ee\u6807**\uff1aRclone \u5b9a\u671f\u5907\u4efd\u91cd\u8981\u6570\u636e\u5230 dufs \u7684 WebDAV \u7aef\u53e3\\n4. **\u4e34\u65f6\u5171\u4eab**\uff1a\u9700\u8981\u7ed9\u540c\u4e8b\u4f20\u6587\u4ef6\u65f6\uff0c\u4e22\u5230 dufs \u7684\u5171\u4eab\u76ee\u5f55\uff0c\u7ed9\u4e2a\u94fe\u63a5\u5373\u53ef\\n\\n\u5177\u4f53\u90e8\u7f72\u65b9\u5f0f\u89c1\u6559\u7a0b\uff1a[Dufs \u90e8\u7f72](../docs/tutorials/docker/deployments/Dufs\u90e8\u7f72)\\n\\n## \u603b\u7ed3\\n\\ndufs \u7528\u6700\u7b80\u5355\u7684\u65b9\u5f0f\u8986\u76d6\u4e86\u4e2a\u4eba\u7f51\u76d8\u7684\u6838\u5fc3\u9700\u6c42\uff1a\u6587\u4ef6\u7ba1\u7406 + WebDAV + \u6743\u9650\u63a7\u5236\u3002\u5bf9\u4e8e\u4e0d\u9700\u8981 Nextcloud \u90a3\u79cd\u5168\u5bb6\u6876\u529f\u80fd\u7684\u7528\u6237\u6765\u8bf4\uff0cdufs \u662f\u4e00\u4e2a\u975e\u5e38\u4f18\u96c5\u7684\u9009\u62e9\u2014\u2014Rust \u5e26\u6765\u7684\u4f4e\u8d44\u6e90\u5360\u7528\u548c\u5355\u4e8c\u8fdb\u5236\u90e8\u7f72\uff0c\u8ba9\u7ef4\u62a4\u6210\u672c\u51e0\u4e4e\u4e3a\u96f6\u3002\\n\\n\u5982\u679c\u4f60\u7684\u9700\u6c42\u66f4\u590d\u6742\uff08\u591a\u4eba\u534f\u4f5c\u3001\u5728\u7ebf\u7f16\u8f91\u3001\u63d2\u4ef6\u751f\u6001\uff09\uff0cNextcloud \u4f9d\u7136\u662f\u66f4\u597d\u7684\u9009\u62e9\u3002\u4f46\u5bf9\u4e8e\u300c\u6211\u5c31\u662f\u60f3\u7b80\u5355\u5b58\u53d6\u6587\u4ef6\u3001\u6302\u4e2a\u7f51\u76d8\u3001\u505a\u4e2a\u5907\u4efd\u76ee\u6807\u300d\u8fd9\u4e2a\u573a\u666f\uff0cdufs \u503c\u5f97\u4e00\u8bd5\u3002"},{"id":"jenkins-fullstack-deploy-guide","metadata":{"permalink":"/blog/jenkins-fullstack-deploy-guide","editUrl":"https://github.com/yunqilee69/cludix-doc/tree/master/blog/2026-06-22-jenkins\u5168\u94fe\u8def\u90e8\u7f72\u5b9e\u6218.md","source":"@site/blog/2026-06-22-jenkins\u5168\u94fe\u8def\u90e8\u7f72\u5b9e\u6218.md","title":"Jenkins \u5168\u94fe\u8def\u90e8\u7f72\u5b9e\u6218\uff1a\u4ece Git Push \u5230 Nginx \u91cd\u8f7d","description":"\u672c\u6587\u4ee5\u672c\u7ad9\uff08Docusaurus \u6587\u6863\u7ad9\uff09\u4e3a\u4f8b\uff0c\u5b8c\u6574\u8bb0\u5f55\u5982\u4f55\u642d\u5efa\u4e00\u6761\u4ece\u4ee3\u7801\u63d0\u4ea4\u5230\u7ad9\u70b9\u66f4\u65b0\u7684 Jenkins \u81ea\u52a8\u5316\u90e8\u7f72\u94fe\u8def\u3002\u5185\u5bb9\u6db5\u76d6\u672c\u5730 Jenkins \u6784\u5efa\u4ea7\u7269\u3001FRP \u5185\u7f51\u7a7f\u900f\u6253\u901a Webhook\u3001SSH \u4e0a\u4f20\u5230\u4e91\u670d\u52a1\u5668\u5e76\u91cd\u8f7d Nginx\u3002","date":"2026-06-22T00:00:00.000Z","tags":[{"inline":true,"label":"Jenkins","permalink":"/blog/tags/jenkins"},{"inline":true,"label":"CI/CD","permalink":"/blog/tags/ci-cd"},{"inline":true,"label":"FRP","permalink":"/blog/tags/frp"},{"inline":true,"label":"Nginx","permalink":"/blog/tags/nginx"},{"inline":true,"label":"Docusaurus","permalink":"/blog/tags/docusaurus"},{"inline":true,"label":"\u81ea\u52a8\u5316\u90e8\u7f72","permalink":"/blog/tags/\u81ea\u52a8\u5316\u90e8\u7f72"}],"readingTime":8.93,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"jenkins-fullstack-deploy-guide","title":"Jenkins \u5168\u94fe\u8def\u90e8\u7f72\u5b9e\u6218\uff1a\u4ece Git Push \u5230 Nginx \u91cd\u8f7d","tags":["Jenkins","CI/CD","FRP","Nginx","Docusaurus","\u81ea\u52a8\u5316\u90e8\u7f72"],"date":"2026-06-22T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"\u81ea\u5efa\u8f7b\u91cf\u5316\u7f51\u76d8\u4e0e WebDAV\uff1a\u7528 dufs \u66ff\u4ee3\u91cd\u91cf\u7ea7\u65b9\u6848","permalink":"/blog/self-hosted-lightweight-cloud-webdav"},"nextItem":{"title":"\u9605\u8bfb\u6307\u5357\uff1aBlog \u548c\u6587\u6863\u5e94\u8be5\u600e\u4e48\u8bfb","permalink":"/blog/automated-deployment-pipeline"}},"content":"\u672c\u6587\u4ee5\u672c\u7ad9\uff08Docusaurus \u6587\u6863\u7ad9\uff09\u4e3a\u4f8b\uff0c\u5b8c\u6574\u8bb0\u5f55\u5982\u4f55\u642d\u5efa\u4e00\u6761\u4ece\u4ee3\u7801\u63d0\u4ea4\u5230\u7ad9\u70b9\u66f4\u65b0\u7684 Jenkins \u81ea\u52a8\u5316\u90e8\u7f72\u94fe\u8def\u3002\u5185\u5bb9\u6db5\u76d6\u672c\u5730 Jenkins \u6784\u5efa\u4ea7\u7269\u3001FRP \u5185\u7f51\u7a7f\u900f\u6253\u901a Webhook\u3001SSH \u4e0a\u4f20\u5230\u4e91\u670d\u52a1\u5668\u5e76\u91cd\u8f7d Nginx\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u67b6\u6784\u80cc\u666f\\n\\n\u6211\u76ee\u524d\u7684\u5f00\u53d1\u73af\u5883\u662f\u8fd9\u6837\u7684\uff1aJenkins \u8dd1\u5728\u672c\u5730\u5185\u7f51\u673a\u5668\u4e0a\uff0c\u800c Nginx \u7ad9\u70b9\u90e8\u7f72\u5728\u4e91\u670d\u52a1\u5668\u4e0a\u3002\u8fd9\u4f1a\u5e26\u6765\u4e00\u4e2a\u6838\u5fc3\u77db\u76fe\u2014\u2014GitHub Webhook \u65e0\u6cd5\u76f4\u63a5\u56de\u8c03\u5185\u7f51\u7684 Jenkins\u3002\\n\\n\u89e3\u51b3\u65b9\u6848\u662f **FRP \u5185\u7f51\u7a7f\u900f**\uff1a\u5728\u4e91\u670d\u52a1\u5668\u90e8\u7f72 FRP \u670d\u52a1\u7aef\uff0c\u672c\u5730\u90e8\u7f72 FRP \u5ba2\u6237\u7aef\uff0c\u5c06 Jenkins \u7aef\u53e3\u6620\u5c04\u5230\u4e91\u670d\u52a1\u5668\u516c\u7f51\u7aef\u53e3\u3002\u800c Jenkins \u6784\u5efa\u5b8c\u6210\u540e\uff0c\u4e3b\u52a8 SSH \u8fde\u63a5\u4e91\u670d\u52a1\u5668\u4e0a\u4f20\u6587\u4ef6\u2014\u2014\u8fd9\u662f\u51fa\u7ad9\u8fde\u63a5\uff0c\u4e0d\u53d7 NAT \u9650\u5236\uff0c\u4e0d\u9700\u8981 FRP \u53c2\u4e0e\u3002\\n\\n```\\n\u5f00\u53d1\u8005 push \u2192 GitHub Webhook \u2192 \u4e91\u670d\u52a1\u5668:31000 (FRP\u7a7f\u900f) \u2192 \u672c\u5730 Jenkins \u89e6\u53d1\\n\u2192 \u62c9\u4ee3\u7801 \u2192 pnpm install \u2192 pnpm run build \u2192 SSH\u76f4\u8fde\u4e91\u670d\u52a1\u5668\u4e0a\u4f20 build/ \u2192 nginx reload \u2192 \u7ad9\u70b9\u66f4\u65b0\\n```\\n\\n| \u89d2\u8272 | \u804c\u8d23 |\\n|------|------|\\n| \u672c\u5730\u670d\u52a1\u5668 | Docker \u8fd0\u884c Jenkins + FRP \u5ba2\u6237\u7aef\uff0c\u8d1f\u8d23\u62c9\u53d6\u4ee3\u7801\u548c\u6784\u5efa |\\n| \u4e91\u670d\u52a1\u5668 | \u8fd0\u884c Nginx + FRP \u670d\u52a1\u7aef\uff0c\u8d1f\u8d23\u6258\u7ba1\u7ad9\u70b9\u548c\u63a5\u6536\u90e8\u7f72 |\\n\\n> FRP \u5185\u7f51\u7a7f\u900f\u7684\u5b8c\u6574\u914d\u7f6e\u4e0d\u662f\u672c\u6587\u91cd\u70b9\uff0c\u8bf7\u5148\u53c2\u8003 [FRP \u5185\u7f51\u7a7f\u900f\u6559\u7a0b](/docs/tutorials/network/frp-nat) \u5b8c\u6210\u642d\u5efa\u3002\\n\\n## \u524d\u63d0\u6761\u4ef6\\n\\n| \u7ec4\u4ef6 | \u4f4d\u7f6e | \u8981\u6c42 |\\n|------|------|------|\\n| Jenkins | \u672c\u5730\u670d\u52a1\u5668 | Docker \u90e8\u7f72\uff0c\u7aef\u53e3\u6620\u5c04 31000:8080 |\\n| Node.js | Jenkins \u5168\u5c40\u5de5\u5177 | \u901a\u8fc7 NodeJS Plugin \u81ea\u52a8\u7ba1\u7406\uff08\u4e0b\u6587\u914d\u7f6e\uff09 |\\n| FRP | \u672c\u5730 + \u4e91\u670d\u52a1\u5668 | \u5df2\u914d\u7f6e\u5e76\u8fde\u901a |\\n| Nginx | \u4e91\u670d\u52a1\u5668 | \u5df2\u5b89\u88c5\uff0cSSH \u670d\u52a1\u5f00\u542f |\\n| SSH \u514d\u5bc6 | \u672c\u5730 \u2192 \u4e91\u670d\u52a1\u5668 | \u5df2\u914d\u7f6e |\\n\\nJenkins \u7684 Docker \u90e8\u7f72\u8bf7\u53c2\u8003 [Docker \u5b89\u88c5 Jenkins](/docs/tutorials/ci/jenkins/install-jenkins)\\n\\nSSH \u514d\u5bc6\u914d\u7f6e\u8bf7\u53c2\u8003 [Jenkins SSH \u5bc6\u94a5\u914d\u7f6e](/docs/tutorials/ci/jenkins/jenkins-ssh-config)\u3002\\n\\n---\\n\\n## \u7b2c\u4e00\u6b65\uff1aJenkins \u63d2\u4ef6\u51c6\u5907\\n\\nJenkins \u521d\u59cb\u5316\u65f6\uff0c\u76f4\u63a5\u9009\u62e9 **\u5b89\u88c5\u793e\u533a\u63a8\u8350\u63d2\u4ef6\uff08Install suggested plugins\uff09** \u5373\u53ef\u3002\u8fd9\u4f1a\u81ea\u52a8\u88c5\u597d Pipeline\u3001Git\u3001Credentials Binding \u7b49\u6838\u5fc3\u63d2\u4ef6\u3002\\n\\n\u4e4b\u540e\u989d\u5916\u624b\u52a8\u5b89\u88c5\u4e24\u4e2a\u63d2\u4ef6\uff1a\\n\\n| \u989d\u5916\u63d2\u4ef6 | \u7528\u9014 |\\n|----------|------|\\n| **NodeJS** | \u81ea\u52a8\u4e0b\u8f7d\u548c\u7ba1\u7406 Node.js \u7248\u672c\uff0c\u65e0\u9700\u624b\u52a8\u5728\u5bb9\u5668\u4e2d\u5b89\u88c5 |\\n| **Publish Over SSH** | SSH \u4f20\u8f93\u6587\u4ef6 + \u8fdc\u7a0b\u6267\u884c\u547d\u4ee4 |\\n\\n\u8fdb\u5165 **Manage Jenkins \u2192 Plugins \u2192 Available plugins**\uff0c\u4f9d\u6b21\u641c\u7d22\u5b89\u88c5\u5373\u53ef\u3002\\n\\n---\\n\\n## \u7b2c\u4e8c\u6b65\uff1a\u914d\u7f6e Node.js \u5168\u5c40\u5de5\u5177\\n\\n\u5b89\u88c5 NodeJS \u63d2\u4ef6\u540e\uff0c\u9700\u8981\u5728\u5168\u5c40\u5de5\u5177\u914d\u7f6e\u4e2d\u6dfb\u52a0 Node.js\uff1a\\n\\n1. \u8fdb\u5165 **Manage Jenkins \u2192 Global Tool Configuration**\uff08\u65e7\u7248\u4e3a **Manage Jenkins \u2192 Global Tool Configuration**\uff09\\n2. \u6eda\u52a8\u5230 **NodeJS installations** \u533a\u57df\uff0c\u70b9\u51fb **Add NodeJS**\\n3. \u586b\u5199\u914d\u7f6e\uff1a\\n\\n| \u5b57\u6bb5 | \u503c |\\n|------|------|\\n| Name | `NodeJS-20` |\\n| Install automatically | \u2705 \u52fe\u9009 |\\n| Version | \u9009\u62e9\u9879\u76ee\u6240\u9700\u7684\u7248\u672c\uff08\u672c\u9879\u76ee\u8981\u6c42 \u2265 20.0\uff0c\u5982 `20.18.0`\uff09 |\\n| Global npm packages | `pnpm@9` |\\n\\n4. \u70b9\u51fb **Save**\\n\\n> **\u539f\u7406**\uff1a\u9996\u6b21\u6784\u5efa\u65f6\uff0c\u63d2\u4ef6\u4f1a\u81ea\u52a8\u4ece nodejs.org \u4e0b\u8f7d\u5bf9\u5e94\u7248\u672c\u7684 Node.js \u5230 `$JENKINS_HOME/tools/` \u4e0b\uff0c\u540e\u7eed\u6784\u5efa\u76f4\u63a5\u590d\u7528\uff0c\u65e0\u9700\u5728\u5bb9\u5668\u91cc\u624b\u52a8\u5b89\u88c5\u3002\u5bb9\u5668\u91cd\u5efa\u540e\u53ea\u8981\u6302\u8f7d\u4e86 `/var/jenkins_home`\uff0c\u5df2\u4e0b\u8f7d\u7684 Node.js \u4e5f\u4e0d\u4f1a\u4e22\u5931\u3002\\n>\\n> **\u6ce8\u610f**\uff1aNodeJS \u63d2\u4ef6\u4e0b\u8f7d\u7684\u662f glibc \u7f16\u8bd1\u7684\u4e8c\u8fdb\u5236\u6587\u4ef6\u3002\u672c\u6587\u4f7f\u7528\u7684 `jenkins/jenkins:lts-jdk21` \u57fa\u4e8e Debian\uff08glibc\uff09\uff0c\u53ef\u4ee5\u6b63\u5e38\u8fd0\u884c\u3002**\u4e0d\u8981\u4f7f\u7528 Alpine \u955c\u50cf**\uff0c\u5426\u5219\u4f1a\u56e0\u4e3a musl libc \u4e0d\u517c\u5bb9\u5bfc\u81f4 `node: not found`\u3002\\n\\n### \u4e3a\u4ec0\u4e48\u7528 pnpm \u800c\u4e0d\u662f npm ci\\n\\n\u672c\u9879\u76ee\u6700\u521d\u4f7f\u7528 `npm ci` \u5b89\u88c5\u4f9d\u8d56\uff0c\u5728 Jenkins \u4e2d\u9047\u5230\u4e86 `Exit handler never called!` \u62a5\u9519\u3002\u8fd9\u662f npm \u5185\u90e8 `agent-base` \u7684\u4e00\u4e2a\u5df2\u77e5 bug\uff08[npm/cli#9386](https://github.com/npm/cli/issues/9386)\uff09\uff1a\u5f53\u4f9d\u8d56\u6570\u8d85\u8fc7\u5e76\u53d1\u8fde\u63a5\u4e0a\u9650\uff08\u9ed8\u8ba4 15\uff09\u4e14\u7f51\u7edc\u51fa\u73b0\u8d85\u65f6\u65f6\uff0c\u8bf7\u6c42\u4f1a\u6c38\u4e45\u5361\u4f4f\u3002\\n\\n\u6539\u7528 pnpm \u540e\uff0c\u5f97\u76ca\u4e8e\u5176\u5168\u5c40 store + \u786c\u94fe\u63a5\u673a\u5236\uff0c**\u9996\u6b21\u6784\u5efa\u540e\u51e0\u4e4e\u4e0d\u9700\u8981\u7f51\u7edc\u8bf7\u6c42**\uff0c\u4ece\u6839\u672c\u4e0a\u7ed5\u5f00\u4e86\u8fd9\u4e2a\u95ee\u9898\u3002\u540c\u65f6\u6784\u5efa\u901f\u5ea6\u4e5f\u6709\u663e\u8457\u63d0\u5347\uff1a\\n\\n```\\nnpm ci\uff08\u9996\u6b21\uff09\uff1a    \u4ece registry \u4e0b\u8f7d\u6240\u6709\u5305 \u2192 \u5168\u91cf\u5199\u5165 node_modules\\npnpm install\uff08\u9996\u6b21\uff09\uff1a\u4ece registry \u4e0b\u8f7d\u5230\u5168\u5c40 store \u2192 \u786c\u94fe\u63a5\u5230 node_modules\\npnpm install\uff08\u540e\u7eed\uff09\uff1a\u76f4\u63a5\u4ece store \u786c\u94fe\u63a5\u5230 node_modules\uff08\u51e0\u4e4e\u96f6\u7f51\u7edc\u8bf7\u6c42\uff09\\n```\\n\\npnpm \u5168\u5c40 store \u4f4d\u4e8e `~/.local/share/pnpm/store`\uff08\u5bb9\u5668\u5185\u5373 `/var/jenkins_home/.local/share/pnpm/store`\uff09\uff0c\u7531\u4e8e\u5df2\u6302\u8f7d `-v /opt/jenkins/data:/var/jenkins_home`\uff0cstore \u4f1a\u968f\u5bb9\u5668\u6301\u4e45\u5316\uff0c\u91cd\u5efa\u5bb9\u5668\u4e5f\u4e0d\u4f1a\u4e22\u5931\u3002\\n\\n---\\n\\n## \u7b2c\u4e09\u6b65\uff1a\u914d\u7f6e SSH \u670d\u52a1\u5668\\n\\n\u8fdb\u5165 **Manage Jenkins \u2192 System**\uff0c\u627e\u5230 **SSH Servers** \u533a\u57df\uff1a\\n\\n```\\nName:             cloud-server\\nHostname:         \u4f60\u7684\u4e91\u670d\u52a1\u5668\u516c\u7f51 IP\\nUsername:         deploy\\nRemote Directory: /\\n```\\n\\n> **\u26a0\ufe0f Remote Directory \u662f\u6839\u76ee\u5f55\uff0c\u4e0d\u662f\u5bb6\u76ee\u5f55\uff01**\\n>\\n> Publish Over SSH \u63d2\u4ef6\u4e2d\uff0c`remoteDirectory`\uff08Jenkinsfile \u91cc\u7684\uff09**\u59cb\u7ec8\u62fc\u63a5\u5728** SSH Server \u914d\u7f6e\u7684 Remote Directory **\u4e4b\u540e**\uff0c\u5373\u4f7f\u4ee5 `/` \u5f00\u5934\u4e5f\u662f\u5982\u6b64\u3002\u4e5f\u5c31\u662f\u8bf4\uff0c\u6700\u7ec8\u8fdc\u7a0b\u8def\u5f84 = `SSH Server Remote Directory` + `remoteDirectory`\u3002\\n>\\n> \u4e3e\u4f8b\uff1a\u5982\u679c SSH Server \u7684 Remote Directory \u8bbe\u4e3a `/home/deploy`\uff0cJenkinsfile \u91cc `remoteDirectory: \'/var/www/cludix-doc\'`\uff0c\u5b9e\u9645\u6587\u4ef6\u4f1a\u4f20\u5230 `/home/deploy/var/www/cludix-doc`\u2014\u2014\u8fd9\u4e0d\u662f\u6211\u4eec\u60f3\u8981\u7684\u3002\\n>\\n> **\u6b63\u786e\u505a\u6cd5**\uff1a\u5c06 SSH Server \u7684 Remote Directory \u8bbe\u4e3a `/`\uff0c\u8ba9 Jenkinsfile \u4e2d\u7684 `remoteDirectory` \u4f7f\u7528\u7edd\u5bf9\u8def\u5f84 `/var/www/cludix-doc`\uff0c\u8fd9\u6837\u62fc\u63a5\u540e\u624d\u662f\u6b63\u786e\u7684\u90e8\u7f72\u8def\u5f84\u3002\\n\\n\u70b9\u51fb **Advanced** \u914d\u7f6e\u8ba4\u8bc1\uff08\u5bc6\u94a5\u8ba4\u8bc1\u63a8\u8350\uff09\uff0c\u70b9\u51fb **Test Configuration** \u786e\u8ba4\u8fde\u901a\u3002\\n\\n---\\n\\n## \u7b2c\u56db\u6b65\uff1a\u914d\u7f6e Git \u51ed\u636e\\n\\n\u8fdb\u5165 **Manage Jenkins \u2192 Credentials \u2192 System \u2192 Global credentials**\uff1a\\n\\n| \u5b57\u6bb5 | \u503c |\\n|------|------|\\n| Kind | Username with password |\\n| ID | `git-credentials` |\\n| Username | \u4f60\u7684 GitHub \u7528\u6237\u540d |\\n| Password | GitHub Personal Access Token |\\n\\n---\\n\\n## \u7b2c\u4e94\u6b65\uff1a\u914d\u7f6e GitHub Webhook\\n\\n\u56e0\u4e3a FRP \u5df2\u5c06 Jenkins \u6620\u5c04\u5230\u4e91\u670d\u52a1\u5668\u7aef\u53e3\uff0cGitHub \u53ef\u4ee5\u56de\u8c03\u5230\uff1a\\n\\n```\\nhttp://\u4f60\u7684\u4e91\u670d\u52a1\u5668IP:31000/github-webhook/\\n```\\n\\n**GitHub \u4ed3\u5e93 \u2192 Settings \u2192 Webhooks \u2192 Add webhook**\uff1a\\n\\n```\\nPayload URL:  http://\u4f60\u7684\u4e91\u670d\u52a1\u5668IP:31000/github-webhook/\\nContent type: application/json\\nEvents:       Just the push event\\n```\\n\\nJenkins Pipeline \u4efb\u52a1\u4e2d\u52fe\u9009 **Build Triggers \u2192 GitHub hook trigger for GITScm polling**\u3002\\n\\n---\\n\\n## \u7b2c\u516d\u6b65\uff1a\u521b\u5efa Pipeline \u4efb\u52a1\\n\\n1. **New Item** \u2192 \u8f93\u5165\u540d\u79f0 \u2192 \u9009\u62e9 **Pipeline** \u2192 OK\\n2. \u52fe\u9009 **This project is parameterized**\uff08\u53ef\u9009\uff0c\u65b9\u4fbf\u5207\u6362\u5206\u652f\uff09\uff1a\\n\\n```\\n\u53c2\u6570\u540d: BRANCH\\n\u7c7b\u578b: String Parameter\\n\u9ed8\u8ba4\u503c: main\\n```\\n\\n3. Pipeline \u533a\u57df\uff0cDefinition \u9009\u62e9 **Pipeline script**\uff0c\u7c98\u8d34\u4ee5\u4e0b\u5185\u5bb9\u3002\\n\\n---\\n\\n## Jenkinsfile \u5b8c\u6574\u5185\u5bb9\\n\\n```groovy\\npipeline {\\n    agent any\\n\\n    // \u4f7f\u7528 NodeJS Plugin \u7ba1\u7406\u7684 Node.js \u73af\u5883\\n    // \u540d\u79f0\u5fc5\u987b\u4e0e Global Tool Configuration \u4e2d\u914d\u7f6e\u7684\u4e00\u81f4\\n    tools {\\n        nodejs \'NodeJS-20\'\\n    }\\n\\n    environment {\\n        // ===== Git \u914d\u7f6e =====\\n        GIT_REPO    = \'https://github.com/yunqilee69/cludix-doc.git\'\\n        GIT_CRED    = \'git-credentials\'\\n\\n        // ===== SSH \u90e8\u7f72\u914d\u7f6e\uff08\u4e91\u670d\u52a1\u5668\uff09 =====\\n        SSH_SERVER  = \'cloud-server\'\\n        REMOTE_DIR  = \'/var/www/cludix-doc\'\\n\\n        // ===== \u6784\u5efa\u4ea7\u7269\u76ee\u5f55\uff08Docusaurus \u8f93\u51fa\u5230 build/\uff09 =====\\n        BUILD_DIR   = \'build\'\\n    }\\n\\n    stages {\\n\\n        // ==================== \u9636\u6bb51\uff1a\u62c9\u53d6\u4ee3\u7801 ====================\\n        stage(\'Checkout\') {\\n            steps {\\n                echo \'\ud83d\udccc \u62c9\u53d6\u4ee3\u7801...\'\\n                git branch: \\"${params.BRANCH ?: \'main\'}\\",\\n                    credentialsId: \\"${GIT_CRED}\\",\\n                    url: \\"${GIT_REPO}\\"\\n            }\\n        }\\n\\n        // ==================== \u9636\u6bb52\uff1a\u5b89\u88c5\u4f9d\u8d56 ====================\\n        stage(\'Install Dependencies\') {\\n            steps {\\n                echo \'\ud83d\udce6 \u5b89\u88c5\u4f9d\u8d56\uff08pnpm + \u6dd8\u5b9d\u955c\u50cf\uff09...\'\\n                sh \'\'\'\\n                    pnpm config set registry https://registry.npmmirror.com\\n                    pnpm install --frozen-lockfile\\n                \'\'\'\\n            }\\n        }\\n\\n        // ==================== \u9636\u6bb53\uff1a\u6784\u5efa ====================\\n        stage(\'Build\') {\\n            steps {\\n                echo \'\ud83d\udd28 \u6784\u5efa Docusaurus \u9879\u76ee...\'\\n                sh \'pnpm run build\'\\n            }\\n            post {\\n                success {\\n                    echo \'\u2705 \u6784\u5efa\u6210\u529f\uff0cbuild \u76ee\u5f55\u5df2\u751f\u6210\'\\n                    sh \'ls -lh build/ | head -10\'\\n                }\\n            }\\n        }\\n\\n        // ==================== \u9636\u6bb54\uff1a\u90e8\u7f72\u5230\u4e91\u670d\u52a1\u5668 ====================\\n        stage(\'Deploy to Cloud\') {\\n            steps {\\n                echo \'\ud83d\ude80 \u901a\u8fc7 SSH \u90e8\u7f72\u5230\u4e91\u670d\u52a1\u5668...\'\\n\\n                sshPublisher(\\n                    continueOnError: false,\\n                    failOnError: true,\\n                    publishers: [\\n                        sshPublisherDesc(\\n                            configName: \\"${SSH_SERVER}\\",\\n                            verbose: true,\\n                            transfers: [\\n                                sshTransfer(\\n                                    // Docusaurus \u6784\u5efa\u4ea7\u7269\u5728 build/ \u76ee\u5f55\\n                                    sourceFiles: \'build/**/*\',\\n                                    // \u53bb\u6389 build \u524d\u7f00\uff0c\u907f\u514d\u8fdc\u7a0b\u51fa\u73b0 build/build/ \u5d4c\u5957\\n                                    removePrefix: \'build\',\\n                                    remoteDirectory: \\"${REMOTE_DIR}\\",\\n                                    execCommand: \\"\\"\\"\\n                                        echo \'\ud83d\udcc1 \u6587\u4ef6\u4f20\u8f93\u5b8c\u6210\'\\n\\n                                        # \u5907\u4efd\u5f53\u524d\u7248\u672c\\n                                        BACKUP_DIR=\\"/var/www/backups/\\\\$(date +%Y%m%d_%H%M%S)\\"\\n                                        sudo mkdir -p \\\\${BACKUP_DIR}\\n                                        sudo cp -r ${REMOTE_DIR}/* \\\\${BACKUP_DIR}/ 2>/dev/null || true\\n                                        echo \\"\ud83d\udce6 \u5df2\u5907\u4efd\u81f3 \\\\${BACKUP_DIR}\\"\\n\\n                                        # \u4fee\u6b63\u6587\u4ef6\u6743\u9650\\n                                        sudo chown -R www-data:www-data ${REMOTE_DIR}\\n                                        sudo chmod -R 755 ${REMOTE_DIR}\\n\\n                                        # \u68c0\u6d4b Nginx \u914d\u7f6e\u5e76\u91cd\u8f7d\\n                                        echo \'\ud83d\udd04 \u91cd\u8f7d Nginx...\'\\n                                        sudo nginx -t && sudo systemctl reload nginx\\n\\n                                        echo \'\u2705 \u90e8\u7f72\u5b8c\u6210\uff01\'\\n                                    \\"\\"\\"\\n                                )\\n                            ]\\n                        )\\n                    ]\\n                )\\n            }\\n        }\\n    }\\n\\n    post {\\n        success {\\n            echo \'\ud83c\udf89 \u6d41\u6c34\u7ebf\u6267\u884c\u6210\u529f\uff01\u7ad9\u70b9\u5df2\u66f4\u65b0\u3002\'\\n        }\\n        failure {\\n            echo \'\u274c \u6d41\u6c34\u7ebf\u6267\u884c\u5931\u8d25\uff0c\u8bf7\u68c0\u67e5\u65e5\u5fd7\'\\n        }\\n        always {\\n            echo \'\ud83e\uddf9 \u6d41\u6c34\u7ebf\u7ed3\u675f\'\\n        }\\n    }\\n}\\n```\\n\\n---\\n\\n## \u4e91\u670d\u52a1\u5668 Nginx \u914d\u7f6e\\n\\n\u4e91\u670d\u52a1\u5668 `/etc/nginx/conf.d/cludix-doc.conf`\uff1a\\n\\n```nginx\\nserver {\\n    listen       80;\\n    server_name  your-domain.com;\\n\\n    root /var/www/cludix-doc;\\n    index index.html;\\n\\n    # SPA \u8def\u7531\u652f\u6301\uff08Docusaurus \u9700\u8981\uff09\\n    location / {\\n        try_files $uri $uri/ /index.html;\\n    }\\n\\n    # \u9759\u6001\u8d44\u6e90\u7f13\u5b58\\n    location ~* \\\\.(js|css|png|jpg|jpeg|gif|ico|svg|woff2?)$ {\\n        expires 30d;\\n        add_header Cache-Control \\"public, immutable\\";\\n    }\\n\\n    # \u7981\u6b62\u8bbf\u95ee\u9690\u85cf\u6587\u4ef6\\n    location ~ /\\\\. {\\n        deny all;\\n    }\\n}\\n```\\n\\n\u4e91\u670d\u52a1\u5668 sudo \u514d\u5bc6\u914d\u7f6e\uff1a\\n\\n```bash\\nsudo visudo\\n\\n# \u6dfb\u52a0\\ndeploy ALL=(ALL) NOPASSWD: /usr/sbin/nginx -t, /usr/bin/systemctl reload nginx, /bin/mkdir, /bin/cp, /usr/bin/chown, /bin/chmod\\n```\\n\\n---\\n\\n## \u7aef\u5230\u7aef\u9a8c\u8bc1\\n\\n```bash\\n# 1. FRP \u8fde\u901a\u6027\\ncurl http://\u4f60\u7684\u4e91\u670d\u52a1\u5668IP:31000    # \u8fd4\u56de Jenkins \u9875\u9762\\n\\n# 2. SSH \u8fde\u901a\u6027\\nssh deploy@\u4f60\u7684\u4e91\u670d\u52a1\u5668IP \\"echo ok\\"\\n\\n# 3. Webhook \u8fde\u901a\u6027\uff08GitHub \u4ed3\u5e93 Settings \u2192 Webhooks\uff09\\n# \u6700\u8fd1\u4e00\u6b21 Delivery \u72b6\u6001\u7801 200\\n\\n# 4. \u624b\u52a8\u89e6\u53d1\u6784\u5efa\uff08Jenkins \u2192 Build Now\uff09\\n# \u5168\u9636\u6bb5\u7eff\u706f \u2705\\n\\n# 5. \u9a8c\u8bc1\u7ad9\u70b9\\ncurl -I http://your-domain.com   # 200 OK\\n```\\n\\n\u5b8c\u6574\u94fe\u8def\uff1a\\n\\n```\\ngit push \u2192 GitHub Webhook \u2192 \u4e91\u670d\u52a1\u5668:31000 (FRP\u7a7f\u900f) \u2192 \u672c\u5730 Jenkins\\n\u2192 Checkout \u2192 pnpm install \u2192 pnpm run build\\n\u2192 SSH \u4e0a\u4f20 build/ \u5230\u4e91\u670d\u52a1\u5668 \u2192 nginx -t \u2192 systemctl reload nginx\\n\u2192 \u7ad9\u70b9\u66f4\u65b0 \u2705\\n```\\n\\n---\\n\\n## \u5e38\u89c1\u95ee\u9898\\n\\n| \u95ee\u9898 | \u539f\u56e0 | \u89e3\u51b3 |\\n|------|------|------|\\n| `Exit handler never called!` | npm \u7684 `agent-base` bug\uff0c\u4f9d\u8d56\u8d85\u8fc7 15 \u4e2a\u5e76\u53d1\u8fde\u63a5\u4e14\u7f51\u7edc\u8d85\u65f6\u65f6\u89e6\u53d1 | \u4f7f\u7528 pnpm \u66ff\u4ee3 npm ci\uff08\u672c\u6587\u65b9\u6848\uff09\uff0c\u6216 `npm ci --maxsockets 1000` |\\n| `npm ci` \u5931\u8d25 | \u65e0 `package-lock.json` \u6216\u4e0a\u8ff0 bug | \u6539\u7528 pnpm\uff08\u672c\u6587\u65b9\u6848\uff09\uff0c\u6216 `npm install` |\\n| SSH \u4f20\u8f93\u8d85\u65f6 | \u6587\u4ef6\u8fc7\u5927 | \u5148 `tar` \u6253\u5305\u518d\u4f20\u8f93 |\\n| `nginx -t` \u5931\u8d25 | Nginx \u914d\u7f6e\u8bed\u6cd5\u9519\u8bef | \u670d\u52a1\u5668\u624b\u52a8 `nginx -t` \u6392\u67e5 |\\n| `sudo: no tty` | sudo \u9700\u8981 TTY | \u914d\u7f6e `NOPASSWD`\uff0c\u53c2\u8003 [SSH \u914d\u7f6e\u6587\u6863](/docs/tutorials/ci/jenkins/jenkins-ssh-config) |\\n| \u6587\u4ef6\u4f20\u8f93\u5230\u9519\u8bef\u8def\u5f84 | SSH Server \u7684 Remote Directory \u662f\u6839\u524d\u7f00\uff0c`remoteDirectory` \u662f\u76f8\u5bf9\u62fc\u63a5 | SSH Server \u7684 Remote Directory \u8bbe\u4e3a `/`\uff0c\u8ba9 Jenkinsfile \u7528\u7edd\u5bf9\u8def\u5f84 |\\n| \u6587\u4ef6\u5d4c\u5957 build/build/ | `removePrefix` \u672a\u914d\u7f6e | \u786e\u8ba4 `removePrefix: \'build\'` |\\n| Webhook \u65e0\u6cd5\u89e6\u53d1 | FRP \u4e0d\u901a\u6216\u7aef\u53e3\u672a\u653e\u884c | \u68c0\u67e5 FRP \u72b6\u6001\u548c\u4e91\u670d\u52a1\u5668\u5b89\u5168\u7ec4 |\\n| FRP \u76f8\u5173\u95ee\u9898 | \u2014 | \u53c2\u8003 [FRP \u5185\u7f51\u7a7f\u900f\u6559\u7a0b](/docs/tutorials/network/frp-nat) |\\n\\n---\\n\\n## \u5c0f\u7ed3\\n\\n\u6574\u6761\u94fe\u8def\u6d89\u53ca\u56db\u4e2a\u6838\u5fc3\u73af\u8282\uff1aFRP \u7a7f\u900f\u89e3\u51b3\u5165\u7ad9\u3001Jenkins \u6d41\u6c34\u7ebf\u89e3\u51b3\u6784\u5efa\u3001SSH \u4f20\u8f93\u89e3\u51b3\u90e8\u7f72\u3001Nginx reload \u89e3\u51b3\u751f\u6548\u3002\u6bcf\u4e00\u73af\u90fd\u6709\u72ec\u7acb\u7684\u539f\u5b50\u6587\u6863\u53ef\u4ee5\u6df1\u5165\uff0c\u672c\u6587\u5c06\u5b83\u4eec\u4e32\u8054\u6210\u4e00\u4e2a\u5b8c\u6574\u7684\u4e13\u9898\u3002"},{"id":"automated-deployment-pipeline","metadata":{"permalink":"/blog/automated-deployment-pipeline","editUrl":"https://github.com/yunqilee69/cludix-doc/tree/master/blog/2026-06-17-\u81ea\u52a8\u5316\u90e8\u7f72\u94fe\u8def\u642d\u5efa.md","source":"@site/blog/2026-06-17-\u81ea\u52a8\u5316\u90e8\u7f72\u94fe\u8def\u642d\u5efa.md","title":"\u9605\u8bfb\u6307\u5357\uff1aBlog \u548c\u6587\u6863\u5e94\u8be5\u600e\u4e48\u8bfb","description":"\u8fd9\u4e2a\u7ad9\u70b9\u540c\u65f6\u4fdd\u7559 Blog \u548c\u6587\u6863\u533a\uff1aBlog \u7528\u6765\u627f\u8f7d\u4e00\u4e2a\u4e13\u9898\u3001\u4e00\u6bb5\u6392\u67e5\u8fc7\u7a0b\u6216\u4e00\u4e2a\u8303\u56f4\u6027\u95ee\u9898\uff1b\u6587\u6863\u533a\u5219\u62c6\u6210\u539f\u5b50\u5316\u9875\u9762\uff0c\u8bf4\u660e\u67d0\u4e00\u4e2a\u5177\u4f53\u3001\u6e05\u6670\u3001\u53ef\u590d\u7528\u7684\u4e8b\u60c5\u3002","date":"2026-06-17T00:00:00.000Z","tags":[{"inline":true,"label":"\u9605\u8bfb\u6307\u5357","permalink":"/blog/tags/\u9605\u8bfb\u6307\u5357"},{"inline":true,"label":"Blog","permalink":"/blog/tags/blog"},{"inline":true,"label":"\u6587\u6863\u7ad9","permalink":"/blog/tags/\u6587\u6863\u7ad9"},{"inline":true,"label":"Jenkins","permalink":"/blog/tags/jenkins"}],"readingTime":4.07,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"automated-deployment-pipeline","title":"\u9605\u8bfb\u6307\u5357\uff1aBlog \u548c\u6587\u6863\u5e94\u8be5\u600e\u4e48\u8bfb","tags":["\u9605\u8bfb\u6307\u5357","Blog","\u6587\u6863\u7ad9","Jenkins"]},"unlisted":false,"prevItem":{"title":"Jenkins \u5168\u94fe\u8def\u90e8\u7f72\u5b9e\u6218\uff1a\u4ece Git Push \u5230 Nginx \u91cd\u8f7d","permalink":"/blog/jenkins-fullstack-deploy-guide"}},"content":"\u8fd9\u4e2a\u7ad9\u70b9\u540c\u65f6\u4fdd\u7559 Blog \u548c\u6587\u6863\u533a\uff1aBlog \u7528\u6765\u627f\u8f7d\u4e00\u4e2a\u4e13\u9898\u3001\u4e00\u6bb5\u6392\u67e5\u8fc7\u7a0b\u6216\u4e00\u4e2a\u8303\u56f4\u6027\u95ee\u9898\uff1b\u6587\u6863\u533a\u5219\u62c6\u6210\u539f\u5b50\u5316\u9875\u9762\uff0c\u8bf4\u660e\u67d0\u4e00\u4e2a\u5177\u4f53\u3001\u6e05\u6670\u3001\u53ef\u590d\u7528\u7684\u4e8b\u60c5\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## Blog \u548c\u6587\u6863\u7684\u533a\u522b\\n\\n### Blog\uff1a\u56f4\u7ed5\u4e13\u9898\u89e3\u51b3\u4e00\u7c7b\u95ee\u9898\\n\\nBlog \u66f4\u9002\u5408\u8bb0\u5f55\u201c\u8303\u56f4\u6027\u95ee\u9898\u201d\u3002\u5b83\u4e0d\u4e00\u5b9a\u53ea\u56de\u7b54\u4e00\u4e2a\u547d\u4ee4\u600e\u4e48\u5199\uff0c\u800c\u662f\u628a\u4e00\u4e2a\u4e3b\u9898\u91cc\u7684\u80cc\u666f\u3001\u7ea6\u675f\u3001\u5c1d\u8bd5\u3001\u53d6\u820d\u548c\u7ed3\u8bba\u4e32\u8d77\u6765\u3002\\n\\n\u6bd4\u5982\u5f53\u524d\u8fd9\u7c7b\u201c\u81ea\u52a8\u5316\u90e8\u7f72\u94fe\u8def\u642d\u5efa\u201d\u5185\u5bb9\uff0c\u5c31\u4e0d\u4ec5\u662f Jenkins \u7684\u67d0\u4e2a\u914d\u7f6e\u9879\uff0c\u800c\u662f\u4f1a\u540c\u65f6\u6d89\u53ca\uff1a\\n\\n1. \u4ee3\u7801\u4ed3\u5e93\u89e6\u53d1 Jenkins \u4efb\u52a1\u3002\\n2. Jenkins \u62c9\u53d6\u4ee3\u7801\u5e76\u6267\u884c\u6784\u5efa\u811a\u672c\u3002\\n3. \u6784\u5efa\u73af\u5883\u901a\u8fc7\u4ee3\u7406\u8bbf\u95ee\u5916\u90e8\u4f9d\u8d56\u6e90\u3002\\n4. \u6784\u5efa\u4ea7\u7269\u6253\u5305\u6210 Docker \u955c\u50cf\u3002\\n5. \u955c\u50cf\u63a8\u9001\u5230 Docker \u4ed3\u5e93\u3002\\n6. \u76ee\u6807\u670d\u52a1\u5668\u62c9\u53d6\u955c\u50cf\u5e76\u91cd\u542f\u670d\u52a1\u3002\\n\\n\u8fd9\u4e9b\u5185\u5bb9\u653e\u5728 Blog \u91cc\u66f4\u81ea\u7136\uff0c\u56e0\u4e3a\u8bfb\u8005\u901a\u5e38\u9700\u8981\u5148\u7406\u89e3\u201c\u6574\u6761\u94fe\u8def\u600e\u4e48\u534f\u4f5c\u201d\uff0c\u518d\u5b9a\u4f4d\u81ea\u5df1\u8981\u843d\u5730\u6216\u6392\u67e5\u7684\u73af\u8282\u3002\\n\\nBlog \u8fd8\u9002\u5408\u8bb0\u5f55\uff1a\\n\\n- \u4e00\u4e2a\u4e13\u9898\u7684\u5b8c\u6574\u914d\u7f6e\u8fc7\u7a0b\uff0c\u4f8b\u5982 Jenkins \u7684\u4e00\u7cfb\u5217\u914d\u7f6e\u548c\u4f7f\u7528\u3002\\n- \u4e00\u4e2a bug \u7684\u53d1\u73b0\u3001\u5b9a\u4f4d\u3001\u5c1d\u8bd5\u548c\u6700\u7ec8\u89e3\u51b3\u8fc7\u7a0b\u3002\\n- \u67d0\u4e2a\u65b9\u6848\u4e3a\u4ec0\u4e48\u8fd9\u6837\u8bbe\u8ba1\uff0c\u4ee5\u53ca\u4e2d\u95f4\u653e\u5f03\u8fc7\u54ea\u4e9b\u505a\u6cd5\u3002\\n- \u591a\u4e2a\u5de5\u5177\u7ec4\u5408\u4f7f\u7528\u65f6\u7684\u4e0a\u4e0b\u6587\uff0c\u4f8b\u5982 Jenkins\u3001Docker\u3001\u4ee3\u7406\u3001\u4ed3\u5e93\u548c\u670d\u52a1\u5668\u90e8\u7f72\u4e4b\u95f4\u7684\u5173\u7cfb\u3002\\n\\n### \u6587\u6863\uff1a\u56de\u7b54\u4e00\u4e2a\u539f\u5b50\u95ee\u9898\\n\\n\u6587\u6863\u533a\u66f4\u9002\u5408\u653e\u201c\u539f\u5b50\u5316\u7b54\u6848\u201d\u3002\u6bcf\u4e00\u7bc7\u6587\u6863\u5c3d\u91cf\u53ea\u8bf4\u660e\u4e00\u4e2a\u5177\u4f53\u3001\u6e05\u6670\u3001\u8fb9\u754c\u660e\u786e\u7684\u4e8b\u60c5\uff0c\u8bfb\u8005\u53ef\u4ee5\u76f4\u63a5\u641c\u7d22\u3001\u6253\u5f00\u3001\u7167\u505a\u6216\u5f15\u7528\u3002\\n\\n\u4f8b\u5982\uff1a\\n\\n- Docker \u5982\u4f55\u5b89\u88c5\u3002\\n- \u5982\u4f55\u7528 Docker \u90e8\u7f72 MySQL\u3002\\n- \u67d0\u4e2a Java \u62a5\u9519\u7684\u539f\u56e0\u548c\u5904\u7406\u65b9\u5f0f\u3002\\n- \u67d0\u4e2a Nebula \u6a21\u5757\u7684\u914d\u7f6e\u9879\u3001\u63a5\u53e3\u3001DDL \u6216\u4f7f\u7528\u8bf4\u660e\u3002\\n\\n\u5982\u679c\u4e00\u7bc7\u5185\u5bb9\u53ef\u4ee5\u88ab\u547d\u540d\u6210\u201c\u5982\u4f55\u505a\u67d0\u4e00\u4ef6\u5177\u4f53\u7684\u4e8b\u201d\uff0c\u5e76\u4e14\u4e0d\u4f9d\u8d56\u5f88\u957f\u7684\u524d\u56e0\u540e\u679c\uff0c\u5b83\u901a\u5e38\u66f4\u9002\u5408\u653e\u5728\u6587\u6863\u533a\u3002\\n\\n## \u5f53\u524d\u6587\u6863\u7ad9\u662f\u600e\u4e48\u8bbe\u8ba1\u7684\\n\\n\u8fd9\u4e2a\u7ad9\u70b9\u7684\u9605\u8bfb\u5165\u53e3\u6309\u5185\u5bb9\u7c7b\u578b\u62c6\u5f00\uff1a\\n\\n- **\u4e13\u9898**\uff1a\u5bf9\u5e94 Blog\uff0c\u7528\u6765\u9605\u8bfb\u8de8\u591a\u4e2a\u5de5\u5177\u3001\u914d\u7f6e\u548c\u7cfb\u7edf\u7684\u5927\u578b\u95ee\u9898\u5904\u7406\u8fc7\u7a0b\u3002\\n- **\u6559\u7a0b**\uff1a\u6309 Linux\u3001Windows\u3001macOS\u3001Docker\u3001Kubernetes\u3001CI/CD\u3001Java\u3001\u6570\u636e\u5e93\u3001\u7f51\u7edc\u7b49\u573a\u666f\u7ec4\u7ec7\uff0c\u9002\u5408\u627e\u201c\u600e\u4e48\u505a\u201d\u3002\\n- **\u8e29\u5751**\uff1a\u540c\u6837\u6309\u6280\u672f\u573a\u666f\u5206\u7c7b\uff0c\u9002\u5408\u627e\u201c\u4e3a\u4ec0\u4e48\u51fa\u9519\u3001\u600e\u4e48\u4fee\u201d\u3002\\n- **Nebula**\uff1a\u6309\u6a21\u5757\u7ec4\u7ec7\u6846\u67b6\u80fd\u529b\uff0c\u6bcf\u4e2a\u6a21\u5757\u4e0b\u518d\u62c6\u6210\u6982\u89c8\u3001\u4e1a\u52a1\u80fd\u529b\u3001\u914d\u7f6e\u3001DDL\u3001\u63a5\u53e3\u3001\u8bbe\u8ba1\u5b9e\u73b0\u548c\u4f7f\u7528\u6307\u5357\u3002\\n- **\u641c\u7d22**\uff1a\u7ad9\u70b9\u4f1a\u7d22\u5f15\u6587\u6863\u3001Blog \u548c\u9875\u9762\uff0c\u9002\u5408\u5728\u4e0d\u77e5\u9053\u5206\u7c7b\u65f6\u76f4\u63a5\u68c0\u7d22\u5173\u952e\u5b57\u3002\\n\\n\u6587\u6863\u533a\u7684\u4fa7\u8fb9\u680f\u91c7\u7528\u81ea\u52a8\u751f\u6210\u65b9\u5f0f\uff1a\u65b0\u589e\u5185\u5bb9\u65f6\uff0c\u4f18\u5148\u628a\u6587\u6863\u653e\u8fdb\u5bf9\u5e94\u76ee\u5f55\uff1b\u76ee\u5f55\u9875\u4f7f\u7528 `index.md`\uff1b\u5206\u7c7b\u5143\u6570\u636e\u901a\u8fc7 `_category_.json` \u7ef4\u62a4\u540d\u79f0\u3001\u987a\u5e8f\u548c\u53ef\u70b9\u51fb\u5165\u53e3\u3002\u8fd9\u6837\u53ef\u4ee5\u8ba9\u76ee\u5f55\u7ed3\u6784\u3001\u9875\u9762 URL \u548c\u4fa7\u8fb9\u680f\u5c3d\u91cf\u4fdd\u6301\u7a33\u5b9a\u3002\\n\\n## \u63a8\u8350\u9605\u8bfb\u65b9\u5f0f\\n\\n### \u5148\u5224\u65ad\u81ea\u5df1\u5728\u627e\u4ec0\u4e48\\n\\n\u5982\u679c\u4f60\u60f3\u4e86\u89e3\u4e00\u4e2a\u4e13\u9898\u7684\u5b8c\u6574\u80cc\u666f\uff0c\u5148\u770b Blog\u3002\u4f8b\u5982\u81ea\u52a8\u5316\u90e8\u7f72\u76f8\u5173\u5185\u5bb9\uff0c\u5c31\u5e94\u8be5\u5148\u4ece\u4e13\u9898\u6587\u7ae0\u7406\u89e3 Jenkins\u3001\u811a\u672c\u3001\u4ee3\u7406\u3001Docker \u4ed3\u5e93\u548c\u670d\u52a1\u5668\u90e8\u7f72\u4e4b\u95f4\u7684\u5173\u7cfb\u3002\\n\\n\u5982\u679c\u4f60\u53ea\u60f3\u5b8c\u6210\u4e00\u4e2a\u660e\u786e\u52a8\u4f5c\uff0c\u76f4\u63a5\u53bb\u6587\u6863\u533a\u3002\u4f8b\u5982\u201cDocker \u5b89\u88c5\u201d\u201cDocker \u90e8\u7f72 MySQL\u201d\u201c\u67d0\u4e2a\u62a5\u9519\u600e\u4e48\u4fee\u201d\u8fd9\u7c7b\u95ee\u9898\uff0c\u4e0d\u9700\u8981\u5148\u8bfb\u4e00\u7bc7\u957f\u6587\u3002\\n\\n### \u518d\u9009\u62e9\u5165\u53e3\\n\\n- \u627e\u64cd\u4f5c\u6b65\u9aa4\uff1a\u4f18\u5148\u770b **\u6559\u7a0b**\u3002\\n- \u627e\u6545\u969c\u5904\u7406\uff1a\u4f18\u5148\u770b **\u8e29\u5751**\u3002\\n- \u627e\u6846\u67b6\u6a21\u5757\u8bf4\u660e\uff1a\u4f18\u5148\u770b **Nebula**\u3002\\n- \u627e\u5b8c\u6574\u65b9\u6848\u3001\u6392\u67e5\u8fc7\u7a0b\u3001\u8bbe\u8ba1\u601d\u8def\uff1a\u4f18\u5148\u770b **\u4e13\u9898**\u3002\\n- \u4e0d\u786e\u5b9a\u653e\u5728\u54ea\u91cc\uff1a\u76f4\u63a5\u7528\u641c\u7d22\u3002\\n\\n### \u6700\u540e\u56de\u5230\u539f\u5b50\u6587\u6863\u843d\u5730\\n\\nBlog \u901a\u5e38\u8d1f\u8d23\u628a\u95ee\u9898\u8bb2\u5b8c\u6574\uff0c\u4f46\u771f\u6b63\u843d\u5730\u65f6\uff0c\u4ecd\u7136\u5e94\u8be5\u56de\u5230\u539f\u5b50\u6587\u6863\u786e\u8ba4\u5177\u4f53\u547d\u4ee4\u3001\u914d\u7f6e\u9879\u548c\u6ce8\u610f\u4e8b\u9879\u3002\u4e5f\u5c31\u662f\u8bf4\uff1a\\n\\n1. \u7528 Blog \u5efa\u7acb\u4e0a\u4e0b\u6587\u3002\\n2. \u7528\u6587\u6863\u6267\u884c\u5177\u4f53\u6b65\u9aa4\u3002\\n3. \u9047\u5230\u62a5\u9519\u65f6\u5230\u8e29\u5751\u533a\u68c0\u7d22\u3002\\n4. \u5982\u679c\u95ee\u9898\u8de8\u591a\u4e2a\u73af\u8282\uff0c\u518d\u56de\u5230 Blog \u770b\u5b8c\u6574\u94fe\u8def\u3002\\n\\n## \u540e\u7eed\u5185\u5bb9\u5e94\u8be5\u600e\u4e48\u5199\\n\\n\u540e\u7eed\u65b0\u589e\u5185\u5bb9\u65f6\uff0c\u53ef\u4ee5\u6309\u4e0b\u9762\u7684\u89c4\u5219\u5224\u65ad\u653e\u5728\u54ea\u91cc\uff1a\\n\\n- **\u653e Blog**\uff1a\u4e00\u4e2a\u4e13\u9898\u3001\u4e00\u6761\u94fe\u8def\u3001\u4e00\u6b21\u5b8c\u6574\u6392\u67e5\u3001\u4e00\u4e2a bug \u7684\u89e3\u51b3\u8fc7\u7a0b\u3001\u4e00\u4e2a\u65b9\u6848\u7684\u601d\u8003\u8fc7\u7a0b\u3002\\n- **\u653e\u6587\u6863**\uff1a\u4e00\u4e2a\u660e\u786e\u52a8\u4f5c\u3001\u4e00\u4e2a\u6e05\u6670\u914d\u7f6e\u3001\u4e00\u4e2a\u5177\u4f53\u547d\u4ee4\u3001\u4e00\u4e2a\u53ef\u72ec\u7acb\u590d\u7528\u7684\u95ee\u9898\u7b54\u6848\u3002\\n\\n\u4f8b\u5982 Jenkins \u7684\u4e00\u7cfb\u5217\u914d\u7f6e\u548c\u4f7f\u7528\uff0c\u53ef\u4ee5\u4f5c\u4e3a Blog \u8bb0\u5f55\u5b8c\u6574\u90e8\u7f72\u94fe\u8def\uff1b\u800c\u201cDocker \u5b89\u88c5\u201d\u201cDocker \u90e8\u7f72 MySQL\u201d\u8fd9\u7c7b\u5185\u5bb9\uff0c\u5219\u5e94\u8be5\u62c6\u6210\u72ec\u7acb\u6587\u6863\uff0c\u65b9\u4fbf\u641c\u7d22\u548c\u590d\u7528\u3002\\n\\n\u8fd9\u6837\u7684\u5206\u5de5\u53ef\u4ee5\u8ba9 Blog \u4fdd\u7559\u771f\u5b9e\u7684\u95ee\u9898\u73b0\u573a\uff0c\u4e5f\u8ba9\u6587\u6863\u533a\u4fdd\u6301\u77ed\u3001\u51c6\u3001\u53ef\u68c0\u7d22\u3002"}]}}')}}]);